mapper.select:
SELECT LAST_SEQ
FROM TBL_NO_MASTER
WHERE YEAR = #{year}
AND APPROVAL_FORM_ID = #{formId}
FOR UPDATE

mapper.update:
UPDATE TBL_NO_MASTER
SET LAST_SEQ = LAST_SEQ + 1,
UPDATE_DATE = NOW()
WHERE YEAR = #{year}
AND APPROVAL_FORM_ID = #{formId}

mapper.select:
SELECT COUNT(*)
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND APPROVER_ID = #{processorId}
AND APPROVE_STATUS = '02'
AND APPROVE_TYPE IN ('02', '03')

SELECT
CASE WHEN COUNT(*) = 0 THEN 1 ELSE 0 END
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND STEP_SEQ > (
SELECT STEP_SEQ
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND APPROVER_ID = #{processorId}
)
AND APPROVE_TYPE = '02'

mapper.update:
UPDATE TBL_APRLINE
SET
APPROVE_STATUS = '02'
WHERE DOC_ID = #{docId}
AND STEP_SEQ = #{stepSeq}
AND APPROVE_STATUS = '01'
